            try {
                const toDelete = [];
                // 1. 删除 pending 的 user 消息（如果存在）
                if (pendingUserMessageId.value !== null) {
                    toDelete.push(pendingUserMessageId.value);
                }
                // 2. 兜底：若快照后多出了楼层且当前最后一条是 user，也删掉（避免 pendingUserMessageId 记错导致玩家楼层残留）
