                                finalData = parsed; // 使用解析后的完整 MVU 数据
                            }
                        }
                    }
                    catch (e) {
                        console.warn('⚠️ [App] 解析 <UpdateVariable> 失败，将使用原始变量数据写入:', e);
                    }
                    await createChatMessages([
                        {
                            role: 'assistant',
                            message: message,
                            data: finalData, // 发送完整 MVU 格式
                        },
                    ], { refresh: 'none' });
                    console.log('✅ [App] 已静默记录到酒馆楼层');
